// Compute 4-bit outcode for Cohen-Sutherland algorithm
// Bit 3 (MSB): Top - above ymax
// Bit 2: Bottom - below ymin 
// Bit 1: Right - beyond xmax
// Bit 0 (LSB): Left - before xmin

FUNCTION ComputeOutcode(x, y):
 // Initialize to 0 (inside all regions)
 code = 0

 // Check Left (bit 0)
 IF x < xmin THEN:
 code = code + 1 // Set bit 0

 // Check Right (bit 1)
 IF x > xmax THEN:
 code = code + 2 // Set bit 1

 // Check Bottom (bit 2)
 IF y < ymin THEN:
 code = code + 4 // Set bit 2

 // Check Top (bit 3)
 IF y > ymax THEN:
 code = code + 8 // Set bit 3

 RETURN code

// Example: Point (50, 450) with window (100,100) to (400,400)
// x=50 < xmin=100 → Left bit set → +1
// y=450 > ymax=400 → Top bit set → +8
// Outcode = 9 = 1001 (binary)
